import{_ as t,o,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"CLI Prompts Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cli-prompts.md","filePath":"reference/cli-prompts.md","lastUpdated":null}'),d={name:"reference/cli-prompts.md"};function n(s,e,i,l,c,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="cli-prompts-reference" tabindex="-1">CLI Prompts Reference <a class="header-anchor" href="#cli-prompts-reference" aria-label="Permalink to &quot;CLI Prompts Reference&quot;">​</a></h1><p>Complete reference for every prompt shown when running <code>pnpm create @sogody/experiment</code>.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @sogody/experiment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-experiment</span></span></code></pre></div><p>The project name is a required argument. The CLI exits if it is not provided.</p><h2 id="prompts" tabindex="-1">Prompts <a class="header-anchor" href="#prompts" aria-label="Permalink to &quot;Prompts&quot;">​</a></h2><h3 id="select-boilerplate" tabindex="-1">Select boilerplate <a class="header-anchor" href="#select-boilerplate" aria-label="Permalink to &quot;Select boilerplate&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Select</td></tr><tr><td><strong>Default</strong></td><td><code>product-card</code></td></tr><tr><td><strong>Options</strong></td><td><code>product-card</code>, <code>minimal</code></td></tr></tbody></table><p>Controls which template is used for the generated project.</p><ul><li><code>product-card</code> — Generates a Samsung product card UI with Samsung API integration, <code>ExperimentCard</code> Preact component, and per-variation SCSS. Use for upsell, cross-sell, and product promotion experiments.</li><li><code>minimal</code> — Generates a simple button component with no API integration. Use for CTA copy tests, layout experiments, and anything that doesn&#39;t need product data.</li></ul><hr><h3 id="number-of-variations" tabindex="-1">Number of variations <a class="header-anchor" href="#number-of-variations" aria-label="Permalink to &quot;Number of variations&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Select</td></tr><tr><td><strong>Default</strong></td><td><code>1</code></td></tr><tr><td><strong>Options</strong></td><td><code>1</code>, <code>2</code>, <code>3</code>, <code>4</code>, <code>custom</code></td></tr></tbody></table><p>Controls how many variation directories are generated under <code>src/js/</code>.</p><ul><li><code>1</code> — generates <code>src/js/v1/</code> only (control)</li><li><code>2</code> — generates <code>src/js/v1/</code> and <code>src/js/v2/</code> (A/B)</li><li><code>custom</code> — prompts for a number between 1 and 10</li></ul><hr><h3 id="window-namespace" tabindex="-1">Window namespace <a class="header-anchor" href="#window-namespace" aria-label="Permalink to &quot;Window namespace&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Text</td></tr><tr><td><strong>Default</strong></td><td><code>sgd</code></td></tr><tr><td><strong>Validation</strong></td><td>Must be a valid JavaScript identifier</td></tr></tbody></table><p>Sets the <code>globalObject</code> field in <code>experiment.config.js</code>. The IIFE bundle registers itself as <code>window[globalObject]</code> — for example, <code>window.sgd</code>.</p><p>Keep the default <code>sgd</code> unless it conflicts with another experiment running on the same Adobe Target page.</p><hr><h3 id="include-emergency-brake" tabindex="-1">Include emergency brake <a class="header-anchor" href="#include-emergency-brake" aria-label="Permalink to &quot;Include emergency brake&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Confirm</td></tr><tr><td><strong>Default</strong></td><td><code>true</code></td></tr></tbody></table><p>Sets <code>includeEmergencyBrake</code> in <code>experiment.config.js</code>. When <code>true</code>, the generated experiment wraps its logic in an Adobe Target kill-switch that can be toggled off without a code deployment.</p><p>Always leave enabled for experiments going to production.</p><hr><h3 id="enable-e2e-testing" tabindex="-1">Enable E2E testing <a class="header-anchor" href="#enable-e2e-testing" aria-label="Permalink to &quot;Enable E2E testing&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Confirm</td></tr><tr><td><strong>Default</strong></td><td><code>false</code></td></tr></tbody></table><p>When <code>true</code>, generates <code>e2e/</code>, <code>playwright.config.js</code>, and adds <code>pnpm test:e2e</code> to <code>package.json</code>. The CLI also runs <code>pnpm playwright install</code> after project setup.</p><p>If <code>false</code>, none of the E2E files are generated and Playwright is not installed.</p><hr><h3 id="base-url-e2e-only" tabindex="-1">Base URL <em>(E2E only)</em> <a class="header-anchor" href="#base-url-e2e-only" aria-label="Permalink to &quot;Base URL _(E2E only)_&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Text</td></tr><tr><td><strong>Default</strong></td><td><code>https://samsung.com</code></td></tr><tr><td><strong>Condition</strong></td><td>Only shown when E2E is enabled</td></tr></tbody></table><p>The root URL for Playwright tests. Written to <code>e2e/config.js</code> as <code>urlsConfig.baseUrl</code>.</p><hr><h3 id="market-e2e-only" tabindex="-1">Market <em>(E2E only)</em> <a class="header-anchor" href="#market-e2e-only" aria-label="Permalink to &quot;Market _(E2E only)_&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Select</td></tr><tr><td><strong>Default</strong></td><td>—</td></tr><tr><td><strong>Condition</strong></td><td>Only shown when E2E is enabled</td></tr></tbody></table><p>Selects which Samsung market(s) to run E2E tests against. Multi-country groups (SEBN, SENA, SEIB) generate one test per country. See the <a href="/reference/markets.html">Markets Reference</a> for all available options.</p><hr><h3 id="run-smoke-test-e2e-only" tabindex="-1">Run smoke test <em>(E2E only)</em> <a class="header-anchor" href="#run-smoke-test-e2e-only" aria-label="Permalink to &quot;Run smoke test _(E2E only)_&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Type</strong></td><td>Confirm</td></tr><tr><td><strong>Default</strong></td><td><code>false</code></td></tr><tr><td><strong>Condition</strong></td><td>Only shown when E2E is enabled</td></tr></tbody></table><p>When <code>true</code>, the CLI runs <code>pnpm build</code> and then <code>pnpm test:e2e</code> immediately after project setup. Useful to verify the scaffold is working end-to-end before you start developing.</p>',42)])])}const m=t(d,[["render",n]]);export{g as __pageData,m as default};
